sys_script_include.script:
var api_dtech_chat = Class.create();
api_dtech_chat.CONST_TASK_CHAT_CONFIGURATION = "dtech_teams_task";  // this must match what is in the config table
api_dtech_chat.CONST_TEMPLATE_CHAT_CONFIGURATION = "dtech_teams_template";  // this must match what is in the config table
api_dtech_chat.CONST_TEMPLATE_TASK_CHAT_CONFIGURATION = "dtech_teams_template_task";  // this must match what is in the config table
api_dtech_chat.CONST_REQUEST_CHAT_CONFIGURATION = "dtech_teams_request";  // this must match what is in the config table
api_dtech_chat.prototype = {
    initialize: function() {
    },

	getChatInformation: function(users, userId, tableName, item_sys_id){
		var docIntUtil = new x_dtll2_contentint.DocIntUtilities();  // cross scope call
		var lChatInfo = {};
		lChatInfo.userId = userId;
		// if user emails not passed in, then go get them
		if(!users || users==undefined || users=='undefined'){
			var arrUserIds = userId.split(',');
			var arrUserEmails = [];
			arrUserIds.forEach(function(userSysId){
				var lProfile = new UserInfoScripts().loadProfileInfo(userSysId.toString());
				arrUserEmails.push(lProfile.email);
			});
			users = arrUserEmails.join(",");
		}
		lChatInfo.users = users;
		lChatInfo.tableName = tableName;
		lChatInfo.item_sys_id = item_sys_id;
		var hasLinkWithObjectInformation = false;
		switch(tableName){
			case api_dtech_common.CONST_DTECH_TASK_TABLE_NAME:
				hasLinkWithObjectInformation = true;
				lChatInfo.chatIntegrationId = api_dtech_chat.CONST_TASK_CHAT_CONFIGURATION;
				break;
			case api_dtech_common.CONST_DTECH_TEMPLATE_TABLE_NAME:
				hasLinkWithObjectInformation = true;
				lChatInfo.chatIntegrationId = api_dtech_chat.CONST_TEMPLATE_CHAT_CONFIGURATION;
				break;
			case api_dtech_common.CONST_DTECH_TEMPLATE_TASK_TABLE_NAME:
				hasLinkWithObjectInformation = true;
				lChatInfo.chatIntegrationId = api_dtech_chat.CONST_TEMPLATE_TASK_CHAT_CONFIGURATION;
				break;
			case api_dtech_common.CONST_DTECH_REQUEST_TABLE_NAME:
				hasLinkWithObjectInformation = true;
				lChatInfo.chatIntegrationId = api_dtech_chat.CONST_REQUEST_CHAT_CONFIGURATION;
				break;
		}

		if(hasLinkWithObjectInformation==true){
			try{
				lChatInfo.deepLink = docIntUtil.getChatDeepLink(lChatInfo.chatIntegrationId, tableName, item_sys_id, users);
			} catch(er){
				lChatInfo.errorGettingLInk = JSON.stringify(er);
			}
		}

		return lChatInfo;
	},

    type: 'api_dtech_chat'
};
